
'use client';

import { MapContainer, TileLayer, Marker, Popup, Polyline, useMap } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import { useEffect, type FC } from 'react';

// This prevents the error "Map container is already initialized" by ensuring the map is only rendered client-side.
// We also make it a named export to be used with next/dynamic.

const busIcon = new L.Icon({
    iconUrl: 'https://cdn-icons-png.flaticon.com/64/503/503184.png',
    iconSize: [32, 32],
    iconAnchor: [16, 32],
    popupAnchor: [0, -32],
});

const stopIcon = new L.Icon({
    iconUrl: 'https://cdn-icons-png.flaticon.com/64/684/684908.png',
    iconSize: [24, 24],
    iconAnchor: [12, 24],
    popupAnchor: [0, -24],
});


type MarkerData = {
    position: [number, number];
    popupText: string;
    type: 'bus' | 'stop';
};

type MapComponentProps = {
    markers: MarkerData[];
    center: [number, number];
    zoom?: number;
    polyline?: [number, number][];
};

function MapViewUpdater({ center, zoom }: { center: [number, number], zoom: number }) {
  const map = useMap();
  useEffect(() => {
    map.setView(center, zoom);
  }, [map, center, zoom]);
  return null;
}

export const MapComponent: FC<MapComponentProps> = ({ markers, center, zoom = 13, polyline }) => {
    return (
        <MapContainer center={center} zoom={zoom} scrollWheelZoom={false} className="h-full w-full rounded-lg z-0">
            <TileLayer
                attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
                url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            />
            {markers.map((marker, idx) => (
                <Marker key={idx} position={marker.position} icon={marker.type === 'bus' ? busIcon : stopIcon}>
                    <Popup>{marker.popupText}</Popup>
                </Marker>
            ))}
            {polyline && <Polyline pathOptions={{ color: 'hsl(var(--primary))' }} positions={polyline} />}
            <MapViewUpdater center={center} zoom={zoom} />
        </MapContainer>
    );
};
